/* ── helpers ─────────────────────────────────────────────────────────────── */
function b2b(s){var b=atob(s),a=new Uint8Array(b.length);for(var i=0;i<b.length;i++)a[i]=b.charCodeAt(i);return a;}
function el(id){return document.getElementById(id);}
function sf(s){if(!s)return '';return (''+s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function hl(t,q){if(!t||!q)return sf(t||'');var tl=t.toLowerCase(),ql=q.toLowerCase(),i=tl.indexOf(ql);if(i<0)return sf(t);return sf(t.slice(0,i))+'<span class="hl">'+sf(t.slice(i,i+q.length))+'</span>'+sf(t.slice(i+q.length));}
/* 收藏夹辅助函数 */
function isFavorited(skinId) {
  return favorites.items.hasOwnProperty(skinId);
}
function toggleFavorite(skinId, skinName, panelType) {
  if (isFavorited(skinId)) {
    // 移除收藏
    delete favorites.items[skinId];
    showToast('已移除收藏: ' + (skinName || skinId));
  } else {
    // 添加收藏
    var skinData = db[skinId] || {};
    favorites.items[skinId] = {
      id: skinId,
      name: skinName || skinData.n || skinId,
      type: getSkinType(skinId),
      category: favorites.settings.defaultCategory,
      addedDate: Date.now(),
      panel: panelType || 'w'
    };
    showToast('已收藏: ' + (skinName || skinId));
  }
  saveFavorites();
  renderFavoritesSidebar();
  // 更新相关卡片上的收藏按钮状态
  updateFavoriteButtons(skinId);
}
function getSkinType(skinId) {
  if (skinId.startsWith('101') || skinId.startsWith('102') || skinId.startsWith('103') ||
      skinId.startsWith('104') || skinId.startsWith('105') || skinId.startsWith('107') ||
      skinId.startsWith('108') || skinId.startsWith('602')) {
    return 'weapon';
  } else if (skinId.startsWith('403') || skinId.startsWith('413') || skinId.startsWith('401') ||
             skinId.startsWith('421') || skinId.startsWith('404') || skinId.startsWith('405') ||
             skinId.startsWith('407') || skinId.startsWith('402') || skinId.startsWith('510') ||
             skinId.startsWith('520') || skinId.startsWith('411') || skinId.startsWith('703') ||
             skinId.startsWith('801') || skinId.startsWith('500') || skinId.startsWith('430')) {
    return 'clothing';
  } else {
    return 'other';
  }
}
function saveFavorites() {
  try {
    localStorage.setItem('pubg_favorites', JSON.stringify(favorites));
  } catch (e) {
    console.error('保存收藏夹失败:', e);
  }
}
function loadFavorites() {
  try {
    var data = localStorage.getItem('pubg_favorites');
    if (data) {
      var parsed = JSON.parse(data);
      // 简单版本迁移检查
      if (parsed.version && parsed.version >= 2) {
        favorites = parsed;
      } else if (Array.isArray(parsed)) {
        // 旧版本数组格式，迁移到新格式
        favorites.items = {};
        parsed.forEach(function(item) {
          if (item && item.id) {
            favorites.items[item.id] = {
              id: item.id,
              name: item.name || item.id,
              type: getSkinType(item.id),
              category: favorites.settings.defaultCategory,
              addedDate: item.addedDate || Date.now(),
              panel: item.panel || 'w'
            };
          }
        });
        saveFavorites();
      }
    }
  } catch (e) {
    console.error('加载收藏夹失败:', e);
  }
}
function updateFavoriteButtons(skinId) {
  // 更新所有包含此skinId的卡片上的收藏按钮
  var buttons = document.querySelectorAll('.fav-btn[data-id="' + skinId + '"]');
  buttons.forEach(function(btn) {
    if (isFavorited(skinId)) {
      btn.className = 'fav-btn active';
      btn.title = '取消收藏';
      btn.innerHTML = '★';
    } else {
      btn.className = 'fav-btn';
      btn.title = '添加到收藏';
      btn.innerHTML = '☆';
    }
  });
}
function cpy(t){if(navigator.clipboard){navigator.clipboard.writeText(t).catch(function(){fb(t);});}else{fb(t);}var n=t.split('\n').length;showToast('已复制'+(n>1?' '+n+'行':''));}
function fb(t){var a=document.createElement('textarea');a.value=t;a.style.cssText='position:fixed;opacity:0';document.body.appendChild(a);a.select();try{document.execCommand('copy');}catch(e){}document.body.removeChild(a);}
function showToast(m){var t=el('toast');t.textContent=m;t.className='toast show';clearTimeout(toastT);toastT=setTimeout(function(){t.className='toast';},2400);}
function mkCard(id,name,cls,selMark,q){
  var sel=selMark!==null&&selMark!==undefined;
  var h='<div class="card '+cls+(sel?' sel':'')+'" data-id="'+sf(id)+'" data-nm="'+sf(name)+'">';
  if(sel&&selMark!=='')h+='<span class="smk">'+sf(selMark)+'</span>';
  // 收藏按钮
  if (isFavorited(id)) {
    h+='<button class="fav-btn active" data-id="'+sf(id)+'" title="取消收藏">★</button>';
  } else {
    h+='<button class="fav-btn" data-id="'+sf(id)+'" title="添加到收藏">☆</button>';
  }
  var v=db[id]||{};
  h+='<div class="card-body">';
  if(v.img){
    h+='<div class="thumb" title="预览"><img src="'+sf(v.img)+'" alt="'+sf(name)+'"/></div>';
  }else{
    h+='<div class="thumb" title="预览">'+sf((name||'').charAt(0))+'</div>';
  }
  h+='<div class="card-main">';
  h+='<div class="ctop"><div class="cname">'+(q?hl(name,q):sf(name))+'</div><div class="cid">'+sf(id)+'</div></div>';
  h+='<div class="cfields"><div class="fld"><div class="flbl">关联</div><div class="fval">'+sf(v.r||'—')+'</div></div>';
  h+='<div class="fld"><div class="flbl">分类</div><div class="fval">'+sf(v.c||'—')+'</div></div>';
  h+='<div class="fld"><div class="flbl">偏移</div><div class="fval">'+sf(v.o||'—')+'</div></div></div>';
  h+='</div></div></div>';
  return h;
}

/* ── DB load ─────────────────────────────────────────────────────────────── */
async function decompressGzip(b64str){
  var bin=atob(b64str),arr=new Uint8Array(bin.length);
  for(var i=0;i<bin.length;i++)arr[i]=bin.charCodeAt(i);
  var stream=new DecompressionStream('gzip');
  var writer=stream.writable.getWriter();
  writer.write(arr);writer.close();
  var reader=stream.readable.getReader();
  var chunks=[];
  while(true){var res=await reader.read();if(res.done)break;chunks.push(res.value);}
  var total=0;for(var i=0;i<chunks.length;i++)total+=chunks[i].length;
  var merged=new Uint8Array(total);var offset=0;
  for(var i=0;i<chunks.length;i++){merged.set(chunks[i],offset);offset+=chunks[i].length;}
  return new TextDecoder().decode(merged);
}
function loadDB(){el('sMain').innerHTML='<div class="loading"><div class="spin"></div><div class="ltxt">正在加载数据库...</div></div>';decompressGzip(DB).then(function(inf){try{db=JSON.parse(inf);if(Array.isArray(db)){var tmp={};for(var i=0;i<db.length;i++){var item=db[i];if(item){if(item.id){tmp[item.id]={n:item.name,r:item.related,c:item.category||'',o:item.offset}}}}db=tmp}el('sMain').innerHTML='<div class="empty"><i>🔍</i>输入关键词开始查询</div>';el('wMain').innerHTML='<div class="empty"><i>🔫</i>搜索或点击武器分类浏览皮肤<br>点击皮肤自动生成所有代码</div>';renderLGrid();buildCatBars();}catch(e){el('sMain').innerHTML='<div class="empty"><i>⚠</i>解析失败:'+e.message+'</div>';console.error(e);}}).catch(function(e){el('sMain').innerHTML='<div class="empty"><i>⚠</i>加载失败:'+e.message+'</div>';console.error(e);});}

