/* ── Perfect skins panel ─────────────────────────────────────────────── */
function renderPerfect(){
  var area=el('pMain');
  if(!PERFECT_SKINS||!db){area.innerHTML='<div class="empty">数据加载中...</div>';return;}
  var h='';
  for(var i=0;i<PERFECT_SKINS.length;i++){
    var p=PERFECT_SKINS[i];
    var wb=p.id.substring(0,6);
    var wi=WEAPONS[wb]||null;
    var wname=wi?wi.n:wb;
    var jjName=db[p.jj]?db[p.jj].n:'';
    var djtxName=db[p.djtx]?db[p.djtx].n:'';
    var jsdhName=db[p.jsdh]?db[p.jsdh].n:'';
    h+='<div class="pf-card" data-pf="'+i+'">';
    h+='<div class="pf-top">';
    h+='<div>';
    h+='<div class="pf-name">'+sf(p.name)+'</div>';
    h+='<div class="pf-wlbl">'+sf(wname)+'</div>';
    h+='</div>';
    h+='<div class="pf-id">'+sf(p.id)+'</div>';
    h+='</div>';
    h+='<div class="pf-tags">';
    h+='<span class="pf-tag jj">&#128247; '+sf(jjName||p.jj)+'</span>';
    h+='<span class="pf-tag djtx">&#128165; '+sf(djtxName||p.djtx)+'</span>';
    h+='<span class="pf-tag jsdh">&#127916; '+sf(jsdhName||p.jsdh)+'</span>';
    h+='</div>';
    h+='<button class="pf-btn" data-pfi="'+i+'">&#9889; 生成全套代码</button>';
    h+='<div class="pf-codes" id="pf-codes-'+i+'" style="display:none"></div>';
    h+='</div>';
  }
  area.innerHTML=h;
  /* Bind generate buttons */
  area.querySelectorAll('[data-pfi]').forEach(function(btn){
    btn.addEventListener('click',function(){
      var idx=parseInt(this.getAttribute('data-pfi'));
      var p=PERFECT_SKINS[idx];
      var codeEl=el('pf-codes-'+idx);
      if(codeEl.style.display==='block'){codeEl.style.display='none';this.textContent='⚡ 生成全套代码';return;}
      /* Generate codes using genWCodes into the code div */
      var wb=p.id.substring(0,6);
      var wi=WEAPONS[wb]||null;
      codeEl.style.display='block';
      this.textContent='▲ 收起';
      genWCodes(p.id,p.name,wb,wi,codeEl);
      codeEl.scrollIntoView({behavior:'smooth',block:'start'});
    });
  });
}

/* ── Comment generator for codes ──────────────────────────────────────── */
function mkComment(wname, slot, skinName){
  /* skinName: just the skin series part e.g. "灵猫魔法师" */
  if(!slot || slot==='主体') return '#'+wname+'改'+skinName;
  return '#'+wname+slot+'改'+skinName;
}

/* ── Archive (配置库) functions ─────────────────────────────────────── */
function saveToArchive(skinName, skinId, codes){
  var entry={id:Date.now(), skinId:skinId, skinName:skinName, codes:codes, ts:new Date().toLocaleTimeString()};
  wArchive.unshift(entry);
  if(wArchive.length>50)wArchive.pop();
  renderArchive();
  el('archSection').style.display='block';
  showToast('已存入配置库: '+skinName);
  /* Update archive badge in tab */
  var badge=document.querySelector('#mt-w .tab-badge');
  if(!badge){var t=el('mt-w');var b=document.createElement('span');b.className='tab-badge';t.appendChild(b);}
  el('mt-w').querySelector('.tab-badge').textContent=wArchive.length;
}
function renderArchive(){
  var list=el('archList');
  if(!wArchive.length){list.innerHTML='<div class="empty" style="padding:16px">暂无存档</div>';return;}
  var h='';
  for(var i=0;i<wArchive.length;i++){
    var e=wArchive[i];
    var codeText=e.codes.join('\n');
    h+='<div class="arch-card">';
    h+='<div class="arch-top"><div class="arch-name">'+sf(e.skinName)+'</div>';
    h+='<div class="arch-id">'+sf(e.skinId)+'</div>';
    h+='<span class="arch-cnt">'+e.codes.length+' 条</span></div>';
    h+='<div style="font-size:9px;color:var(--dm);margin-bottom:6px">'+e.ts+'</div>';
    h+='<div class="arch-btns">';
    h+='<button class="arch-btn cpy" data-arch-cpy="'+sf(codeText)+'">复制代码</button>';
    h+='<button class="arch-btn" data-arch-view="'+i+'">查看</button>';
    h+='<button class="arch-btn del" data-arch-del="'+e.id+'">删除</button>';
    h+='</div>';
    h+='<div class="arch-codes" id="arch-codes-'+e.id+'">'+sf(codeText).replace(/\n/g,'<br>')+'</div>';
    h+='</div>';
  }
  list.innerHTML=h;
  /* Bind buttons */
  list.querySelectorAll('[data-arch-cpy]').forEach(function(btn){
    btn.addEventListener('click',function(){cpy(this.getAttribute('data-arch-cpy'));});
  });
  list.querySelectorAll('[data-arch-view]').forEach(function(btn){
    btn.addEventListener('click',function(){
      var idx=parseInt(this.getAttribute('data-arch-view'));
      var e=wArchive[idx];
      var codeEl=document.getElementById('arch-codes-'+e.id);
      codeEl.classList.toggle('show');
      this.textContent=codeEl.classList.contains('show')?'收起':'查看';
    });
  });
  list.querySelectorAll('[data-arch-del]').forEach(function(btn){
    btn.addEventListener('click',function(){
      var delId=parseInt(this.getAttribute('data-arch-del'));
      wArchive=wArchive.filter(function(e){return e.id!==delId;});
      renderArchive();
      if(!wArchive.length){el('archSection').style.display='none';var b=el('mt-w').querySelector('.tab-badge');if(b)b.remove();}
      else{el('mt-w').querySelector('.tab-badge').textContent=wArchive.length;}
    });
  });
}

