/* ── Lo mode switching ───────────────────────────────────────────────── */
function setLoMode(m){
  loMode=m;
  var modes=['normal','suit','red'];
  var btns=['md-normal','md-suit','md-red'];
  var classes=['on-n','on-s','on-r'];
  for(var i=0;i<modes.length;i++){
    var b=el(btns[i]);if(!b)continue;
    b.className='mdbtn'+(modes[i]===m?' '+classes[i]:'');
  }
  var desc=el('loModeDesc');
  if(m==='normal'){
    if(desc)desc.textContent='点击部位格选中 → 搜索或浏览 → 点击填入';
    /* Clear auto-filled slots when leaving red mode */
    if(loMode==='red'){
      var clearSlots=['mask','gogg','hat','hair','bag','helm','armo','face'];
      for(var ci=0;ci<clearSlots.length;ci++){delete lVals[clearSlots[ci]];}
      renderLGrid();renderLoOut();
    }
    /* Clear auto-filled slots when leaving suit mode */
    if(loMode==='suit'){
      /* Only clear if the face is still the 奥特曼 default */
      if(lVals['face']&&lVals['face'].id===FACE_SUIT){delete lVals['face'];}
      /* Clear bag/helm that were auto-matched */
      delete lVals['bag']; delete lVals['helm'];
      renderLGrid();renderLoOut();
    }
  }else if(m==='suit'){
    if(desc)desc.textContent='套装模式：选衣服自动匹配脸部(奥特曼)，优先显示套装分类';
    /* Auto-browse 套装 category */
    if(db){setActiveBtn('lCatBar','430');var r=[],ks2=Object.keys(db);for(var ii=0;ii<ks2.length&&r.length<120;ii++){var id=ks2[ii],v=db[id];if(id.startsWith('430')&&v.r&&v.r!=='0')r.push([id,v]);}renderLRes(r,'');}
    /* If 衣服 already set, auto-match bag/helm */
    if(lVals['top']){autoMatchBagHelm(lVals['top'].name||lVals['top'].n||'');}
  }else{
    if(desc)desc.textContent='红装模式：默认木乃伊特效，选衣服自动替换专属特效';
    /* Pre-fill 木乃伊 default effects */
    var fxSlots=Object.keys(RED_FX_DEFAULT);
    for(var fi=0;fi<fxSlots.length;fi++){
      var fslot=fxSlots[fi];
      if(!lVals[fslot]){lVals[fslot]=RED_FX_DEFAULT[fslot];}
    }
    /* If 衣服 already filled, try auto-match bag/helm */
    if(lVals['top']){autoMatchFx(lVals['top'].name||lVals['top'].n||'');}
    renderLGrid();renderLoOut();
    /* Auto-browse 套装 category */
    if(db){setActiveBtn('lCatBar','430');var r=[],ks2=Object.keys(db);for(var ii=0;ii<ks2.length&&r.length<120;ii++){var id=ks2[ii],v=db[id];if(id.startsWith('430')&&v.r&&v.r!=='0')r.push([id,v]);}renderLRes(r,'');}
  }
  /* Update face auto-fill */
  if((m==='suit'||m==='red')&&!lVals['face']){
    var faceV=db?db[FACE_SUIT]:null;
    if(faceV){lVals['face']={id:FACE_SUIT,name:faceV.n,n:faceV.n};}
    renderLGrid();renderLoOut();
  }else if(m==='normal'&&lVals['face']&&lVals['face'].id===FACE_SUIT){
    delete lVals['face'];
    renderLGrid();renderLoOut();
  }
  refreshLCards();
}


/* ── auto-match motion effects from skin name ─────────────────────────── */
function autoMatchFx(skinName){
  if(loMode!=='red'||!db||!skinName)return;
  var parts=skinName.split('-').filter(function(p){return p&&p!=='套装';});
  var matched=0;
  for(var i=0;i<RED_FX.length;i++){
    var s=RED_FX[i];
    if(lVals[s.slot])continue;
    var found=false;
    for(var pi=0;pi<parts.length&&!found;pi++){
      var sk=parts[pi].trim();
      if(!sk||sk.length<2)continue;
      var ks=Object.keys(db);
      for(var j=0;j<ks.length&&!found;j++){
        var id=ks[j],v=db[id];
        if(id.startsWith(s.pfx)&&v.n&&v.n.indexOf(s.kw)>=0&&v.n.indexOf(sk)>=0){
          lVals[s.slot]={id:id,name:v.n,n:v.n};matched++;found=true;
        }
      }
    }
  }
  /* Auto-fill 背包(三级) and 头盔(三级) from same series */
  var bagMatched=false,helmMatched=false;
  for(var pi3=0;pi3<parts.length;pi3++){
    var sk3=parts[pi3].trim();
    if(!sk3||sk3.length<2)continue;
    var ks3=Object.keys(db);
    if(!lVals['bag']){
      for(var j3=0;j3<ks3.length;j3++){
        var bid3=ks3[j3],bn3=db[bid3].n||'';
        if(bid3.startsWith('501003')&&bn3.indexOf(sk3)>=0&&bn3.indexOf('背包')>=0){
          lVals['bag']={id:bid3,name:bn3,n:bn3};bagMatched=true;break;
        }
      }
    }
    if(!lVals['helm']){
      for(var j4=0;j4<ks3.length;j4++){
        var hid4=ks3[j4],hn4=db[hid4].n||'';
        if(hid4.startsWith('502003')&&hn4.indexOf(sk3)>=0&&hn4.indexOf('头盔')>=0){
          lVals['helm']={id:hid4,name:hn4,n:hn4};helmMatched=true;break;
        }
      }
    }
    if(bagMatched&&helmMatched)break;
  }

  renderLGrid();renderLoOut();
  var total=matched+(bagMatched?1:0)+(helmMatched?1:0);
  if(total>0){
    var msg='';
    if(matched>0)msg+='动作特效x'+matched+' ';
    if(bagMatched)msg+='背包 ';
    if(helmMatched)msg+='头盔 ';
    showToast('已自动匹配: '+msg.trim());
  }else{
    var fxSlots2=Object.keys(RED_FX_DEFAULT);
    for(var fi2=0;fi2<fxSlots2.length;fi2++){
      if(!lVals[fxSlots2[fi2]]){lVals[fxSlots2[fi2]]=RED_FX_DEFAULT[fxSlots2[fi2]];}
    }
    renderLGrid();renderLoOut();
    showToast('无专属特效，已使用木乃伊默认特效');
  }
  /* Show fx picker hint in grid for unfilled fx slots */
  showFxHints();
}

/* Auto-match bag/helm for 套装 mode */
function autoMatchBagHelm(skinName){
  if(!db||!skinName)return;
  var parts=skinName.split('-').filter(function(p){return p&&p!=='套装';});
  var bagOk=false,helmOk=false;
  for(var pi=0;pi<parts.length;pi++){
    var sk=parts[pi].trim();
    if(!sk||sk.length<2)continue;
    var ks=Object.keys(db);
    if(!lVals['bag']){
      for(var j=0;j<ks.length;j++){
        var bid=ks[j],bn=db[bid].n||'';
        if(bid.startsWith('501003')&&bn.indexOf(sk)>=0&&bn.indexOf('背包')>=0){
          lVals['bag']={id:bid,name:bn,n:bn};bagOk=true;break;
        }
      }
    }
    if(!lVals['helm']){
      for(var j=0;j<ks.length;j++){
        var hid=ks[j],hn=db[hid].n||'';
        if(hid.startsWith('502003')&&hn.indexOf(sk)>=0&&hn.indexOf('头盔')>=0){
          lVals['helm']={id:hid,name:hn,n:hn};helmOk=true;break;
        }
      }
    }
    if(bagOk&&helmOk)break;
  }
  if(bagOk||helmOk){renderLGrid();renderLoOut();showToast('已自动匹配'+(bagOk?' 三级背包':'')+(helmOk?' 三级头盔':''));}
}

/* Show pick-buttons on unfilled fx slots in red mode */
function showFxHints(){
  if(loMode!=='red')return;
  /* For each RED_FX slot that's empty, show a special hint in lgGrid */
  var slotEls=el('lgGrid').querySelectorAll('[data-lcat]');
  for(var i=0;i<slotEls.length;i++){
    var cat=slotEls[i].getAttribute('data-lcat');
    var fxSlot=null;
    for(var j=0;j<RED_FX.length;j++){if(RED_FX[j].slot===cat){fxSlot=RED_FX[j];break;}}
    if(fxSlot&&!lVals[cat]){
      /* Add a pink hint to this slot */
      var existing=slotEls[i].querySelector('.fx-hint');
      if(!existing){
        var hint=document.createElement('span');
        hint.className='fx-hint';
        hint.style.cssText='font-size:9px;color:var(--re);letter-spacing:.3px;margin-left:4px;';
        hint.textContent=fxSlot.kw;
        slotEls[i].appendChild(hint);
      }
    }
  }
}
